Here are pytest‑style unit tests covering happy path, edge cases, and error cases.

```python
import pytest
from math import inf, isnan
from your_module import celsius_to_fahrenheit

def test_happy_path_positive_temperature():
    assert celsius_to_fahrenheit(25) == 77

def test_happy_path_negative_temperature():
    assert celsius_to_fahrenheit(-40) == -40  # Same value in both scales

def test_edge_case_zero():
    assert celsius_to_fahrenheit(0) == 32

def test_edge_case_large_value():
    assert celsius_to_fahrenheit(1e6) == 1e6 * 9/5 + 32

def test_edge_case_small_value():
    assert celsius_to_fahrenheit(-1e6) == -1e6 * 9/5 + 32

def test_edge_case_inf():
    assert celsius_to_fahrenheit(inf) == inf
    assert celsius_to_fahrenheit(-inf) == -inf

def test_error_case_non_numeric_string():
    with pytest.raises(TypeError):
        celsius_to_fahrenheit("abc")

def test_error_case_none():
    with pytest.raises(TypeError):
        celsius_to_fahrenheit(None)

def test_error_case_nan():
    # nan comparisons are special: result should be nan
    result = celsius_to_fahrenheit(float("nan"))
    assert isnan(result)
